query:
SELECT COUNT(*) as total_partenariat_leads FROM leads WHERE leadType = 'PARTENARIAT';
SELECT COUNT(*) as total_candidates FROM partner_candidates;
SELECT COUNT(*) as leads_sans_candidat FROM leads l WHERE l.leadType = 'PARTENARIAT' AND NOT EXISTS (SELECT 1 FROM partner_candidates pc WHERE pc.metaLeadId = l.id);
SELECT l.id, l.firstName, l.lastName, l.email, l.city FROM leads l WHERE l.leadType = 'PARTENARIAT' AND NOT EXISTS (SELECT 1 FROM partner_candidates pc WHERE pc.metaLeadId = l.id) LIMIT 10;

